Use ASP.NET Core's **`WebApplicationFactory<T>`** to create an in-memory test server, then pass its `HttpClient` to the MCP SDK's transport. No real ports needed.

### 1. Add packages

```xml
<PackageReference Include="Microsoft.AspNetCore.Mvc.Testing" Version="9.0.*" />
<PackageReference Include="ModelContextProtocol" Version="0.*" />
```

### 2. Write the test

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using ModelContextProtocol.Client;
using ModelContextProtocol.Protocol.Transport;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>, IAsyncDisposable
{
    private readonly WebApplicationFactory<Program> _factory;
    private IMcpClient? _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _factory = factory;
    }

    private async Task<IMcpClient> CreateClientAsync()
    {
        // WebApplicationFactory gives you an HttpClient that talks
        // to the in-memory test server — no real port is opened.
        var httpClient = _factory.CreateClient();

        var transport = new SseClientTransport(
            new SseClientTransportOptions
            {
                Endpoint = new Uri(httpClient.BaseAddress!, "/mcp"),
                // or "/sse" — match your server's MCP endpoint
            },
            httpClient   // ← inject the test HttpClient
        );

        _client = await McpClientFactory.CreateAsync(transport);
        return _client;
    }

    [Fact]
    public async Task ListTools_ReturnsExpectedTools()
    {
        var client = await CreateClientAsync();

        var tools = await client.ListToolsAsync();

        Assert.NotEmpty(tools);
        Assert.Contains(tools, t => t.Name == "my-tool");
    }

    [Fact]
    public async Task CallTool_ReturnsCorrectResult()
    {
        var client = await CreateClientAsync();

        var result = await client.CallToolAsync(
            "my-tool",
            new Dictionary<string, object?> { ["input"] = "hello" });

        Assert.False(result.IsError);
        Assert.Contains("expected output", result.Content[0].Text);
    }

    public async ValueTask DisposeAsync()
    {
        if (_client is not null)
            await _client.DisposeAsync();
    }
}
```

### Key points

- **`WebApplicationFactory<Program>`** boots your real `Program` / `Startup` pipeline in-process with a test `HttpClient` — full middleware, DI, routing, all exercised.
- **`SseClientTransport`** (or `StreamableHttpClientTransport` for Streamable HTTP) accepts an `HttpClient`, so you inject the one from the factory.
- Override services for testing via `_factory.WithWebHostBuilder(b => b.ConfigureServices(...))`.
- Make sure `Program` is accessible (add `[assembly: InternalsVisibleTo("YourTestProject")]` or use a `public partial class Program { }` marker).
